const original =
  $('Normalize AI Evaluation').item?.json ||
  $json;

const raw =
  $json.output?.[0]?.content?.[0]?.text ||
  $json.output?.[0]?.text ||
  $json.content?.[0]?.text ||
  $json.text ||
  $json.response ||
  $json.message ||
  '';

let clean = String(raw)
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

// Try to extract JSON object if model returned extra text
const firstBrace = clean.indexOf('{');
const lastBrace = clean.lastIndexOf('}');

if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  clean = clean.slice(firstBrace, lastBrace + 1);
}

let ai;

try {
  ai = JSON.parse(clean);
} catch (e) {
  return {
    json: {
      ...original,

      VerifiedScore: original.Score ?? 0,
      VerifiedRecommendation: original.Recommendation || 'NO',
      FinalCV: original.RecommendedCV || 'Strategy & Operations CV',
      VerifiedInterviewProbability: original.InterviewProbability ?? 0,

      SalaryEstimate: '',
      SalaryTarget: '',
      SalaryConfidence: 'LOW',
      SalaryAssumption: 'Not specified',

      VerifiedRisk: 'Verified review returned invalid JSON.',
      VerifiedWhyApply: original.WhyApply || '',
      VerifiedPriority: original.Priority || 'LOW',

      SalaryRange: '',
      Location: original.Location || 'Not specified',
      LocationFit: original.LocationFit || 'UNKNOWN',

      FinalDecision: 'MONITOR',
      ParseError: e.message,

      DedupeKey: original.DedupeKey && original.DedupeKey !== '||'
        ? original.DedupeKey
        : (
            original.JobId ||
            `${original.Company || ''}|${original.Role || ''}|${original.Location || ''}`.toLowerCase()
          )
    }
  };
}

return {
  json: {
    ...original,

    Role: original.Role || ai.role || '',
    Company: original.Company || ai.company || '',
    JobId: original.JobId || ai.job_id || '',
    WorkType: original.WorkType || ai.work_type || '',
    URL: original.URL || ai.url || '',

    VerifiedScore: ai.final_score ?? original.Score ?? 0,
    VerifiedRecommendation: ai.apply || original.Recommendation || 'NO',
    FinalCV: ai.best_cv || original.RecommendedCV || 'Strategy & Operations CV',
    VerifiedInterviewProbability: ai.interview_probability ?? original.InterviewProbability ?? 0,

    SalaryEstimate: ai.salary_range_eur_gross || '',
    SalaryTarget: ai.salary_target_eur_gross || '',
    SalaryConfidence: ai.salary_confidence || 'LOW',
    SalaryAssumption: ai.salary_assumption || 'Not specified',

    VerifiedRisk: ai.biggest_risk || original.MainRisk || '',
    VerifiedWhyApply: ai.why_apply || original.WhyApply || '',
    VerifiedPriority: ai.follow_up_priority || original.Priority || 'LOW',

    SalaryRange: ai.salary_range_eur_gross || '',
    Location: ai.location || original.Location || 'Not specified',
    LocationFit: ai.location_fit || original.LocationFit || 'UNKNOWN',

    FinalDecision: ai.final_decision || 'MONITOR',

    ParseError: '',

    DedupeKey: original.DedupeKey && original.DedupeKey !== '||'
      ? original.DedupeKey
      : (
          ai.dedupe_key ||
          ai.job_id ||
          original.JobId ||
          `${original.Company || ai.company || ''}|${original.Role || ai.role || ''}|${ai.location || original.Location || ''}`.toLowerCase()
        )
  }
};

const extractRawText = (item) =>
  item.json.output?.[0]?.content?.[0]?.text ||
  item.json.output?.[0]?.text ||
  item.json.content?.[0]?.text ||
  item.json.text ||
  item.json.response ||
  item.json.message ||
  '';

const extractJobId = (url) =>
  String(url || '').match(/jobs\/view\/(\d+)/)?.[1] || '';

const locationAllowed = (location) => {
  const loc = String(location || '').toLowerCase();

  if (
    loc.includes('remote europe') ||
    loc.includes('remote emea') ||
    loc.includes('emea · remote') ||
    loc.includes('europe · remote') ||
    loc.includes('remote worldwide') ||
    loc.includes('remote global') ||
    loc.includes('bulgaria')
  ) {
    return true;
  }

  return false;
};

const looksFakeCompany = (company, role) => {
  const c = String(company || '').toLowerCase().trim();
  const r = String(role || '').toLowerCase().trim();

  if (!c) return true;
  if (c === r) return true;

  const blockedExactCompanies = [
    'remote',
    'hybrid',
    'onsite',
    'on-site',
    'on site',
    'full-time',
    'part-time',
    'contract',
    'temporary',
    'internship'
  ];

  if (blockedExactCompanies.includes(c)) return true;

  if (
    c.includes('connections') ||
    c.includes('install linkedin widgets') ||
    c.includes('see all jobs') ||
    c.includes('actively recruiting') ||
    c.includes('actively reviewing applicants') ||
    c.includes('fast growing') ||
    c.includes('promoted by hirer') ||
    c.includes('responses managed off linkedin')
  ) return true;

  const roleWords = [
    'manager', 'director', 'head', 'chief', 'vp',
    'operations', 'revenue', 'strategy', 'business',
    'lead', 'program', 'product', 'commercial', 'revops'
  ];

  const companyLooksLikeRole = roleWords.some(w => c.includes(w));
  if (companyLooksLikeRole) return true;

  return false;
};

const output = [];
const seen = new Set();

for (const item of $input.all()) {
  const raw = extractRawText(item);

  let clean = String(raw)
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  const firstBracket = clean.indexOf('[');
  const lastBracket = clean.lastIndexOf(']');

  if (firstBracket !== -1 && lastBracket !== -1 && lastBracket > firstBracket) {
    clean = clean.slice(firstBracket, lastBracket + 1);
  }

  let parsed;

  try {
    parsed = JSON.parse(clean);
  } catch (e) {
    continue;
  }

  const jobs = Array.isArray(parsed) ? parsed : (parsed.jobs || []);

  for (const j of jobs) {
    if (!j || !j.company || !j.role) continue;
    if (looksFakeCompany(j.company, j.role)) continue;

    const company = String(j.company || '').trim();
    const role = String(j.role || '').trim();
    const location = String(j.location || 'Not specified').trim();
    const workType = String(j.work_type || '').trim();
    const url = String(j.url || '').trim();
    const jobId = extractJobId(url);
    const dedupeKey = (jobId || `${company}|${role}|${location}`).toLowerCase();

    if (!dedupeKey || dedupeKey === '||') continue;

    if (seen.has(dedupeKey)) continue;
    seen.add(dedupeKey);

    const allowed = locationAllowed(location);

    output.push({
      json: {
        Role: role,
        Company: company,
        JobId: jobId,
        Location: location,
        WorkType: workType,
        URL: url,
        LocationAllowed: allowed,
        LocationRejectReason: allowed ? '' : (
          location.toLowerCase().includes('not specified') || location.trim() === ''
            ? 'Location not specified.'
            : 'Country-specific or non-Bulgaria location rejected.'
        ),
        Source: 'LinkedIn',
        Status: 'New',
        Notes: '',
        ParseError: '',
        DedupeKey: dedupeKey
      }
    });
  }
}

return output;

const decodeHtml = (s) =>
  (s || '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");

const extractLinkedInJobUrls = (html) => {
  const urls = html.match(/https:\/\/www\.linkedin\.com\/comm\/jobs\/view\/[^"'<\s]+/gi) || [];
  const seen = new Set();

  return urls
    .map((u) => decodeHtml(u))
    .filter((u) => {
      const id = u.match(/jobs\/view\/(\d+)/)?.[1] || '';
      if (!id || seen.has(id)) return false;
      seen.add(id);
      return true;
    });
};

const cleanText = (html) =>
  decodeHtml(html)
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<\/tr>/gi, '\n')
    .replace(/<\/td>/gi, '\n')
    .replace(/<\/h[1-6]>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\n+/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .split('\n')
    .map(x => x.trim())
    .filter(Boolean)
    .join('\n')
    .trim();

const subject = $json.subject || $json.Subject || '';
const html = $json.html || $json.textAsHtml || $json.text || '';

const urls = extractLinkedInJobUrls(html);

return {
  json: {
    Subject: cleanText(subject),
    EmailText: cleanText(html),
    LinkedInJobUrls: urls,
    LinkedInJobUrlsText: urls.join('\n'),
    Source: 'LinkedIn'
  }
};

const raw =
  $json.output?.[0]?.content?.[0]?.text ||
  $json.output?.[0]?.text ||
  $json.content?.[0]?.text ||
  $json.text ||
  '';

const clean = String(raw)
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let ai;

try {
  ai = JSON.parse(clean);
} catch (e) {
  return {
    json: {
      Role: '',
      Company: '',
      JobId: '',
      Location: 'Not specified',
      WorkType: '',
      URL: '',
      Source: 'LinkedIn',
      Status: 'AI Parse Error',
      Notes: '',
      DedupeKey: '',

      Score: 0,
      InterviewProbability: 0,
      RecommendedCV: 'Strategy & Operations CV',
      Recommendation: 'NO',
      RemoteFit: 'UNKNOWN',
      CountryFit: 'UNKNOWN',
      SeniorityFit: 'UNKNOWN',
      SectorFit: 'UNKNOWN',
      Priority: 'LOW',
      WhyApply: '',
      MainRisk: 'AI returned invalid JSON.',
      ParseError: e.message
    }
  };
}

const role = ai.role || '';
const company = ai.company || '';
const jobId = ai.job_id || '';
const location = ai.location || 'Not specified';
const workType = ai.work_type || '';
const url = ai.url || '';
const dedupeKey = ai.dedupe_key || (jobId || `${company}|${role}|${location}`).toLowerCase();

return {
  json: {
    Role: role,
    Company: company,
    JobId: jobId,
    Location: location,
    WorkType: workType,
    URL: url,
    Source: 'LinkedIn',
    Status: 'New',
    Notes: '',
    DedupeKey: dedupeKey,

    Score: ai.score ?? 0,
    InterviewProbability: ai.interview_probability ?? 0,
    RecommendedCV: ai.recommended_cv || 'Strategy & Operations CV',
    Recommendation: ai.recommendation || 'NO',
    RemoteFit: ai.remote_fit || 'UNKNOWN',
    CountryFit: ai.country_fit || 'UNKNOWN',
    SeniorityFit: ai.seniority_fit || 'UNKNOWN',
    SectorFit: ai.sector_fit || 'UNKNOWN',
    Priority: ai.follow_up_priority || 'LOW',
    WhyApply: ai.why_apply || '',
    MainRisk: ai.main_risk || '',
    ParseError: ''
  }
};

const reason =
  $json.RejectReason ||
  $json.auto_reject_reason ||
  $json.LocationRejectReason ||
  (
    $json.LocationAllowed === false
      ? 'Location rejected.'
      : 'Low score.'
  );

let status = 'Rejected';

if ($json.LocationAllowed === false) {
  status = 'Location Rejected';
} else if ($json.auto_reject_reason === 'DOMAIN') {
  status = 'Domain Rejected';
} else if ($json.auto_reject_reason === 'LANGUAGE') {
  status = 'Language Rejected';
} else if ($json.auto_reject_reason === 'TIMEZONE') {
  status = 'Timezone Rejected';
} else if ($json.auto_reject_reason === 'PROFILE') {
  status = 'Profile Rejected';
} else if ($json.auto_reject_reason === 'LOW_SCORE') {
  status = 'Low Score';
}

return {
  json: {
    ...$json,

    VerifiedScore: $json.Score ?? 0,
    VerifiedRecommendation: 'NO',
    FinalCV: $json.RecommendedCV || 'Strategy & Operations CV',
    VerifiedInterviewProbability: $json.InterviewProbability ?? 0,

    SalaryEstimate: '',
    SalaryTarget: '',
    SalaryConfidence: 'LOW',
    SalaryAssumption: $json.LocationAllowed === false
      ? 'Location rejected'
      : 'Not specified',

    VerifiedRisk: $json.MainRisk || $json.LocationRejectReason || reason,
    VerifiedWhyApply: $json.LocationAllowed === false
      ? 'Rejected by location filter.'
      : ($json.WhyApply || 'Rejected before final evaluation.'),
    VerifiedPriority: 'LOW',

    LocationFit: $json.LocationAllowed === false
      ? 'MISMATCH'
      : ($json.LocationFit || 'UNKNOWN'),

    FinalDecision: 'REJECT',
    RejectReason: reason,
    Status: status
  }
};
